class Solution:
    def possibleBipartition(self, n, dislikes):
        import sys
        sys.setrecursionlimit(10000)
        from collections import defaultdict
        adj = defaultdict(list)
        for a, b in dislikes:
            adj[a].append(b)
            adj[b].append(a)
        color = [0] * (n + 1)
        def dfs(u, c):
            color[u] = c
            for v in adj[u]:
                if color[v] == c:
                    return False
                if color[v] == 0 and not dfs(v, -c):
                    return False
            return True
        for i in range(1, n + 1):
            if color[i] == 0:
                if not dfs(i, 1):
                    return False
        return True

